public boolean checkValueInBST(TreeNode root, int target) {
	if (root == null) return false;
	if (root.val == target) return true;
	if (target < root.val) return checkValueInBST(root.left, target);
	else return checkValueInBST(root.right, target);
}

public int findSmallestValueInBST(TreeNode root) {
	if (root == null) throw new IllegalArgumentException("Tree cannot be empty");
	while (root.left != null) {
		root = root.left;
	}
	return root.val;
}

public int longestSubarrayWithSumK(int[] nums, int k) {
	Map<Integer, Integer> prefixSumMap = new HashMap<>();
	prefixSumMap.put(0, -1); // Base case: prefix sum of 0 at index -1
	int prefixSum = 0;
	int maxLength = 0;
	for (int i = 0; i < nums.length; i++) {
		prefixSum += nums[i];
		if (!prefixSumMap.containsKey(prefixSum)) {
			prefixSumMap.put(prefixSum, i); // Store the first occurrence of this prefix sum
		}
		if (prefixSumMap.containsKey(prefixSum - k)) {
			maxLength = Math.max(maxLength, i - prefixSumMap.get(prefixSum - k));
		}
	}
	return maxLength;
}
